CREATE OR REPLACE VIEW vw_workflows WITH (security_invoker = ON) AS
SELECT
  t.workflow_id,
  calc_workflows_name(t.workflow_id) AS name,
  t.display_name,
  t.title,
  t.color,
  t.description,
  t.identifier,
  t.modified,
  calc_workflows_workflow_steps(t.workflow_id) AS workflow_steps,
  calc_workflows_count_of_non_proposed_steps(t.workflow_id) AS count_of_non_proposed_steps,
  calc_workflows_has_more_than1_step(t.workflow_id) AS has_more_than1_step
FROM workflows t;

CREATE OR REPLACE VIEW vw_workflow_steps WITH (security_invoker = ON) AS
SELECT
  t.workflow_step_id,
  calc_workflow_steps_name(t.workflow_step_id) AS name,
  t.display_name,
  t.workflow,
  t.sequence_position,
  t.assigned_role,
  t.requires_human_approval,
  t.approval_gate,
  t.preceded_by_steps
FROM workflow_steps t;

CREATE OR REPLACE VIEW vw_approval_gates WITH (security_invoker = ON) AS
